const body = $input.first().json.body || {};
const q = String(body.q || '').trim() || 'newer_than:7d';
const limit = Math.max(1, Math.min(50, parseInt(String(body.limit || 10), 10) || 10));
return [{ json: { q, limit } }];

const cfg = $('Configuration').first().json;
const items = $input.all();
if (!items.length || items[0].json?.error) {
  return [{ json: { ok: false, error: 'Gmail inaccessible ou aucun résultat.', emails: [], count: 0 } }];
}
const emails = items.map(item => {
  const m = item.json;
  const headers = m.payload?.headers || [];
  const from = headers.find(h => h.name === 'From')?.value || '';
  const subject = headers.find(h => h.name === 'Subject')?.value || '(sans objet)';
  const date = headers.find(h => h.name === 'Date')?.value || '';
  const match = from.match(/^(.*?)\s*<(.+?)>$/);
  return {
    id: m.id,
    from,
    from_name: (match?.[1] || from).trim(),
    from_email: match?.[2] || from,
    subject,
    date,
    snippet: (m.snippet || '').slice(0, 400),
    source: 'gmail'
  };
}).filter(e => e.id);
return [{ json: { ok: true, emails, count: emails.length, query: cfg.q } }];
